type Message struct {
	ID             string         `json:"id"`
	InboxID        string         `json:"inboxId"`
	InboxIDLegacy  string         `json:"inbox_id"`
	From           EmailAddress   `json:"from"`
	To             []EmailAddress `json:"to"`
	EmailAddress   string         `json:"email_address"`
	FromAddress    string         `json:"from_address"`
